/**
 * InvestmentTermFormModal Component
 *
 * Wraps the InvestmentTermForm in a Material UI Dialog for modal display.
 * Use this component when you want to show the form in a popup dialog.
 *
 * @example
 * ```tsx
 * <InvestmentTermFormModal
 *   open={isModalOpen}
 *   onClose={handleClose}
 *   onSubmit={handleCreate}
 *   onCancel={handleClose}
 *   isLoading={isCreating}
 * />
 * ```
 */
export function InvestmentTermFormModal({
  open,
  onClose,
  title,
  investmentTerm,
  onSubmit,
  onCancel,
  isLoading = false,
  className = '',
}: InvestmentTermFormModalProps): React.ReactElement {
  const isEditMode = Boolean(investmentTerm);
  const modalTitle = title ?? (isEditMode ? 'Edit InvestmentTerm' : 'Create InvestmentTerm');

  // Handle modal close - prevent closing during loading
  const handleClose = () => {
    if (!isLoading) {
      onClose();
    }
  };

  return (
    <Dialog
      open={open}
      onClose={handleClose}
      maxWidth="md"
      fullWidth
      data-testid="modal-investment_term-form"
    >
      <DialogTitle sx={{ m: 0, p: 2, display: "flex", justifyContent: "space-between", alignItems: "center" }}>
        {modalTitle}
        <IconButton
          aria-label="close"
          onClick={handleClose}
          disabled={isLoading}
          data-testid="modal-close-button"
          sx={{ color: (theme) => theme.palette.grey[500] }}
        >
          <CloseIcon />
        </IconButton>
      </DialogTitle>
      <DialogContent dividers>
        <InvestmentTermForm
          investmentTerm={investmentTerm}
          onSubmit={onSubmit}
          onCancel={onCancel}
          isLoading={isLoading}
          className={className}
        />
      </DialogContent>
    </Dialog>
  );
}


